{
  "pool_id": "fast-testing-pool",
  "display_name": "Isolated Fast Testing Pool",
  "resource_limits": {
    "machine_type": "c2-standard-4",
    "cpu_quota": 64,
    "memory_limit_gb": 256,
    "max_monthly_budget_usd": 500,
    "max_instance_runtime_seconds": 600
  },
  "billing_metadata": {
    "cost_center": "agentic-engineering",
    "project_id": "isolated-testing",
    "tags": {
      "owner": "devops-team",
      "env": "sandbox-vpc"
    }
  },
  "scaling_policy": {
    "min_warm_instances": 2,
    "max_instances": 16,
    "scale_out_threshold_percent": 85,
    "idle_timeout_seconds": 300
  },
  "routing_rules": {
    "allowed_job_tags": ["unit-test", "lint", "security-scan"],
    "priority_weight": 100,
    "preemption_allowed": true
  }
}
